import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { writable } from 'svelte/store';
import { hints } from './hints';
import { createGame, createSudoku } from '../../../domain/index';

function createEmptyGrid() {
	return Array.from({ length: 9 }, () => Array(9).fill(0));
}

let game = createGame({ sudoku: createSudoku(createEmptyGrid()) });

const gridState = writable(createEmptyGrid());
const userGridState = writable(createEmptyGrid());
const invalidCellsState = writable([]);

function syncFromGame() {
const view = game.getViewState();
	gridState.set(view.puzzleGrid);
	userGridState.set(view.userGrid);
	invalidCellsState.set(view.invalidCells);
}

syncFromGame();

function createGrid() {
	return {
		subscribe: gridState.subscribe,
		generate(difficulty) {
			const puzzleArray = generateSudoku(difficulty);
			game = createGame({ sudoku: createSudoku(puzzleArray) });
			syncFromGame();
		},

		decodeSencode(sencode) {
			const puzzleArray = decodeSencode(sencode);
			game = createGame({ sudoku: createSudoku(puzzleArray) });
			syncFromGame();
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			if (gridStore) return encodeSudoku(gridStore);
			return encodeSudoku(game.sudoku.getGrid());
		},

		undo() {
			game.undo();
			syncFromGame();
		},

		redo() {
			game.redo();
			syncFromGame();
		},

		canUndo() {
			return game.canUndo();
		},

		canRedo() {
			return game.canRedo();
		},
	};
}

function createUserGrid() {
	return {
		subscribe: userGridState.subscribe,
		set(pos, value) {
			game.guess({ row: pos.y, col: pos.x, value });
			syncFromGame();
		},

		applyHint(pos) {
			hints.useHint();
			const solvedGrid = solveSudoku(game.sudoku.getGrid());
			if (!solvedGrid) return;
			const value = solvedGrid[pos.y][pos.x];
			game.guess({ row: pos.y, col: pos.x, value });
			syncFromGame();
		},
	};
}

export const grid = createGrid();
export const userGrid = createUserGrid();
export const invalidCells = {
subscribe: invalidCellsState.subscribe,
};